/**
 * Editorial "Pourquoi choisir [marque] ?" content for brand pages.
 * Distinct from intro/outro — focuses on target audience, unique angle and key trade-off.
 * brandId → lang → text
 */
export const BRAND_WHY_CHOOSE: Record<string, Partial<Record<string, string>>> = {
  'crypto-com': {
    fr: `La carte Crypto.com est idéale pour les investisseurs qui souhaitent maximiser leurs récompenses en s'engageant dans l'écosystème CRO. Avec cinq niveaux allant de la Midnight Blue gratuite à l'Obsidian exclusive, elle s'adapte à tous les profils — du casual user au holder confirmé. Son principal atout est la profondeur de ses avantages (Spotify, Netflix, lounges aéroports) qui croissent à mesure que le staking augmente, faisant de chaque palier un vrai saut qualitatif.`,
    de: `Die Crypto.com Karte ist ideal für Investoren, die ihre Belohnungen im CRO-Ökosystem maximieren möchten. Mit fünf Stufen — von der kostenlosen Midnight Blue bis zur exklusiven Obsidian — passt sie zu jedem Profil. Hauptvorteil ist die Tiefe der Vorteile (Spotify, Netflix, Airport-Lounges), die mit dem Staking exponentiell zunehmen und jeden Tier-Sprung zum echten qualitativen Sprung machen.`,
    es: `La tarjeta Crypto.com es ideal para inversores que quieren maximizar sus recompensas en el ecosistema CRO. Con cinco niveles — desde la gratuita Midnight Blue hasta la exclusiva Obsidian — se adapta a todos los perfiles. Su principal ventaja es la profundidad de los beneficios (Spotify, Netflix, salones VIP) que crecen a medida que aumenta el staking, convirtiendo cada salto de nivel en una mejora real.`,
    it: `La carta Crypto.com è ideale per gli investitori che vogliono massimizzare le ricompense nell'ecosistema CRO. Con cinque livelli — dalla gratuita Midnight Blue all'esclusiva Obsidian — si adatta a tutti i profili. Il principale punto di forza è la profondità dei benefici (Spotify, Netflix, lounge aeroportuali) che crescono con lo staking, rendendo ogni salto di livello un vero upgrade qualitativo.`,
    en: `The Crypto.com card is ideal for investors looking to maximise rewards within the CRO ecosystem. With five tiers from the free Midnight Blue to the exclusive Obsidian, it adapts to every profile. Its main strength lies in the depth of benefits — Spotify, Netflix, airport lounges — that scale with your staking commitment, making each tier upgrade a genuine qualitative step forward.`,
  },

  'wirex': {
    fr: `Wirex se distingue par son approche multi-devises : plus de 150 cryptos et monnaies fiat accessibles depuis une seule carte Visa. Elle convient particulièrement aux voyageurs fréquents et aux utilisateurs qui manipulent plusieurs devises au quotidien. Le programme Cryptoback™ verse du Bitcoin sur chaque achat en magasin, indépendamment d'un staking requis, ce qui en fait une option solide pour les curieux de crypto sans engagement fort.`,
    de: `Wirex zeichnet sich durch seinen Multi-Währungsansatz aus: über 150 Kryptos und Fiat-Währungen über eine einzige Visa-Karte. Besonders geeignet für Vielreisende und täglich Multi-Währungsnutzer. Das Cryptoback™-Programm zahlt Bitcoin auf jeden Einkauf — ohne Staking-Pflicht — und macht es zur soliden Option für Krypto-Neugierige ohne starke Bindung.`,
    es: `Wirex se distingue por su enfoque multi-divisa: más de 150 criptos y monedas fiat accesibles desde una sola tarjeta Visa. Ideal para viajeros frecuentes y usuarios que gestionan varias divisas. El programa Cryptoback™ paga Bitcoin en cada compra en tienda, sin staking requerido, convirtiéndola en opción sólida para los curiosos de cripto sin compromiso fuerte.`,
    it: `Wirex si distingue per l'approccio multi-valuta: oltre 150 cripto e valute fiat da una singola carta Visa. Ideale per viaggiatori frequenti e utenti che gestiscono più valute quotidianamente. Il programma Cryptoback™ paga Bitcoin su ogni acquisto in negozio senza staking richiesto, rendendola un'opzione solida per i curiosi di cripto senza un forte impegno.`,
    en: `Wirex stands out for its multi-currency approach: over 150 cryptos and fiat currencies accessible from a single Visa card. It suits frequent travellers and users who deal with multiple currencies daily. The Cryptoback™ programme pays Bitcoin on every in-store purchase with no staking required, making it a solid option for the crypto-curious without a heavy commitment.`,
  },

  'nexo': {
    fr: `Nexo est le choix idéal pour les détenteurs de crypto qui veulent que leurs actifs travaillent en parallèle de leurs dépenses. La carte permet d'emprunter contre son portefeuille crypto sans le vendre, tout en continuant à percevoir des intérêts sur ses actifs. C'est une solution orientée "rendement" pour les utilisateurs DeFi-curious qui cherchent à optimiser leur liquidité sans déclencher d'événements fiscaux.`,
    de: `Nexo ist ideal für Krypto-Halter, die ihre Vermögenswerte gleichzeitig für sich arbeiten lassen möchten. Die Karte ermöglicht Ausgaben durch Kreditaufnahme gegen das Portfolio — ohne Verkauf — während Zinsen weiter anfallen. Eine renditenorientierte Lösung für DeFi-Interessierte, die Liquidität optimieren wollen, ohne Steuerereignisse auszulösen.`,
    es: `Nexo es la elección ideal para tenedores de cripto que quieren que sus activos trabajen en paralelo a sus gastos. La tarjeta permite pedir prestado contra la cartera sin venderla, mientras se siguen acumulando intereses. Una solución orientada al rendimiento para los curiosos de DeFi que buscan optimizar su liquidez sin generar eventos fiscales.`,
    it: `Nexo è la scelta ideale per i detentori di cripto che vogliono che i loro asset lavorino in parallelo alle spese. La carta permette di prendere in prestito contro il portafoglio senza venderlo, continuando ad accumulare interessi. Una soluzione orientata al rendimento per i curiosi DeFi che vogliono ottimizzare la liquidità senza generare eventi fiscali.`,
    en: `Nexo is the ideal choice for crypto holders who want their assets working while they spend. The card lets you borrow against your portfolio without selling, while still earning interest on your holdings. A yield-oriented solution for the DeFi-curious who want to optimise liquidity without triggering taxable events.`,
  },

  'bybit': {
    fr: `La carte Bybit est taillée pour les traders actifs qui souhaitent utiliser leurs gains en crypto sans friction au quotidien. Elle propose le meilleur cashback du marché au niveau Gold (8% en BIT) et s'intègre nativement avec le compte Bybit pour une expérience unifiée trading + dépenses. La supervision AMF lui confère une crédibilité réglementaire rare parmi les cartes d'exchange.`,
    de: `Die Bybit-Karte ist für aktive Trader konzipiert, die Krypto-Gewinne reibungslos im Alltag nutzen möchten. Sie bietet das beste Cashback auf dem Markt auf Gold-Stufe (8% in BIT) und integriert sich nativ mit dem Bybit-Konto für ein einheitliches Trading + Ausgaben-Erlebnis. AMF-Aufsicht verleiht ihr seltene regulatorische Glaubwürdigkeit unter Exchange-Karten.`,
    es: `La tarjeta Bybit está diseñada para traders activos que quieren usar sus ganancias cripto sin fricción en el día a día. Ofrece el mejor cashback del mercado en nivel Gold (8% en BIT) y se integra nativamente con la cuenta Bybit para una experiencia unificada de trading y gastos. La supervisión AMF le otorga una credibilidad regulatoria rara entre las tarjetas de exchange.`,
    it: `La carta Bybit è pensata per i trader attivi che vogliono usare i loro guadagni cripto senza attrito nel quotidiano. Offre il miglior cashback del mercato al livello Gold (8% in BIT) e si integra nativamente con il conto Bybit per un'esperienza unificata di trading e spese. La supervisione AMF le conferisce una credibilità regolamentare rara tra le carte degli exchange.`,
    en: `The Bybit card is designed for active traders who want to put their crypto gains to work in daily life. It offers the best cashback on the market at Gold tier (8% in BIT) and integrates natively with the Bybit account for a unified trading-and-spending experience. AMF supervision gives it rare regulatory credibility among exchange cards.`,
  },

  'binance': {
    fr: `La carte Binance est le choix naturel pour les utilisateurs déjà intégrés dans l'écosystème Binance Pay. Le cashback jusqu'à 8% en BNB est parmi les plus généreux du marché, sans staking requis pour démarrer. C'est un choix logique si vous détenez déjà du BNB ou souhaitez bénéficier des services intégrés de la plus grande plateforme d'échange mondiale.`,
    de: `Die Binance-Karte ist die natürliche Wahl für Nutzer, die bereits im Binance Pay-Ökosystem integriert sind. Cashback bis zu 8% in BNB gehört zu den großzügigsten auf dem Markt, ohne Staking-Pflicht für den Einstieg. Eine logische Wahl für BNB-Halter oder Nutzer der weltgrößten Exchange-Plattform.`,
    es: `La tarjeta Binance es la elección natural para usuarios ya integrados en el ecosistema Binance Pay. El cashback de hasta 8% en BNB está entre los más generosos del mercado sin staking requerido para empezar. Una elección lógica para holders de BNB o usuarios de la mayor plataforma de exchange del mundo.`,
    it: `La carta Binance è la scelta naturale per gli utenti già integrati nell'ecosistema Binance Pay. Il cashback fino all'8% in BNB è tra i più generosi del mercato senza staking richiesto per iniziare. Una scelta logica per i detentori di BNB o gli utenti della più grande piattaforma di exchange al mondo.`,
    en: `The Binance card is the natural choice for users already embedded in the Binance Pay ecosystem. Cashback up to 8% in BNB ranks among the most generous on the market, with no staking required to get started. It's the logical pick for BNB holders or users of the world's largest exchange platform.`,
  },

  'okx': {
    fr: `La carte OKX est conçue pour les traders qui veulent une passerelle fluide entre leur compte OKX et leurs dépenses du quotidien. Le cashback en OKB récompense les détenteurs de l'écosystème OKX, et la carte est acceptée partout où Visa est présent. Elle est particulièrement pertinente si vous êtes déjà actif sur la plateforme pour le trading spot, les futures ou les produits Web3.`,
    de: `Die OKX-Karte ist für Trader konzipiert, die eine reibungslose Brücke zwischen ihrem OKX-Konto und Alltagsausgaben wollen. Cashback in OKB belohnt OKX-Ökosystem-Halter, und die Karte wird überall akzeptiert, wo Visa vorhanden ist. Besonders relevant für bestehende Nutzer der Spot-, Futures- oder Web3-Produkte auf OKX.`,
    es: `La tarjeta OKX está diseñada para traders que quieren un puente fluido entre su cuenta OKX y los gastos diarios. El cashback en OKB recompensa a los holders del ecosistema OKX, y la tarjeta es aceptada en cualquier lugar donde Visa esté presente. Especialmente relevante si ya usas la plataforma para trading spot, futuros o productos Web3.`,
    it: `La carta OKX è progettata per i trader che vogliono un ponte fluido tra il loro conto OKX e le spese quotidiane. Il cashback in OKB premia i detentori dell'ecosistema OKX, e la carta è accettata ovunque sia presente Visa. Particolarmente rilevante se sei già attivo sulla piattaforma per il trading spot, i futures o i prodotti Web3.`,
    en: `The OKX card is designed for traders who want a seamless bridge between their OKX account and daily spending. Cashback in OKB rewards OKX ecosystem holders, and the card is accepted wherever Visa is present. It's particularly relevant if you already use the platform for spot trading, futures or Web3 products.`,
  },

  'coinbase': {
    fr: `La carte Coinbase est le choix de référence pour les débutants et les utilisateurs qui privilégient la sécurité réglementaire avant tout. Régulée aux États-Unis, en Europe et au Royaume-Uni, elle offre une confiance institutionnelle rare dans l'espace crypto. Le cashback en crypto (jusqu'à 4%) sans staking requis est accessible dès l'ouverture du compte, sans aucun engagement.`,
    de: `Die Coinbase-Karte ist die Referenzwahl für Einsteiger und Nutzer, die regulatorische Sicherheit priorisieren. In den USA, Europa und UK reguliert, bietet sie seltenes institutionelles Vertrauen im Krypto-Raum. Cashback in Krypto (bis zu 4%) ohne Staking-Pflicht ist ab der Kontoeröffnung zugänglich, ohne jede Bindung.`,
    es: `La tarjeta Coinbase es la elección de referencia para principiantes y usuarios que priorizan la seguridad regulatoria. Regulada en EE.UU., Europa y Reino Unido, ofrece una confianza institucional rara en el espacio cripto. El cashback en cripto (hasta 4%) sin staking requerido es accesible desde la apertura de cuenta, sin ningún compromiso.`,
    it: `La carta Coinbase è la scelta di riferimento per i principianti e gli utenti che privilegiano la sicurezza regolamentare. Regolamentata in USA, Europa e UK, offre una fiducia istituzionale rara nello spazio cripto. Il cashback in cripto (fino al 4%) senza staking richiesto è accessibile fin dall'apertura del conto, senza alcun impegno.`,
    en: `The Coinbase card is the reference choice for beginners and users who prioritise regulatory safety above all. Regulated in the US, Europe and the UK, it offers rare institutional credibility in the crypto space. Crypto cashback (up to 4%) with no staking required is accessible from day one, with zero lock-in.`,
  },

  'bitpanda': {
    fr: `Bitpanda est le premier neobroker européen à proposer une carte Visa directement liée à un portefeuille multi-actifs (crypto, actions, ETF, métaux précieux). Elle convient aux investisseurs européens qui veulent dépenser leurs gains sans passer par une exchange externe. La régulation autrichienne FMA et la conformité MiCA la positionnent comme l'une des options les plus sûres de l'espace pour les résidents UE.`,
    de: `Bitpanda ist der erste europäische Neobroker mit einer Visa-Karte, die direkt mit einem Multi-Asset-Portfolio (Krypto, Aktien, ETF, Edelmetalle) verknüpft ist. Ideal für europäische Investoren, die Gewinne ohne externe Exchange ausgeben möchten. FMA-Regulierung und MiCA-Konformität machen sie zu einer der sichersten Optionen im Bereich für EU-Einwohner.`,
    es: `Bitpanda es el primer neobroker europeo con una tarjeta Visa directamente vinculada a una cartera multi-activo (cripto, acciones, ETF, metales preciosos). Ideal para inversores europeos que quieren gastar sus ganancias sin pasar por un exchange externo. La regulación FMA austriaca y la conformidad MiCA la posicionan como una de las opciones más seguras del espacio para residentes de la UE.`,
    it: `Bitpanda è il primo neobroker europeo con una carta Visa direttamente collegata a un portafoglio multi-asset (cripto, azioni, ETF, metalli preziosi). Ideale per gli investitori europei che vogliono spendere i loro guadagni senza passare per un exchange esterno. La regolamentazione FMA austriaca e la conformità MiCA la posizionano come una delle opzioni più sicure dello spazio per i residenti UE.`,
    en: `Bitpanda is the first European neobroker with a Visa card directly linked to a multi-asset portfolio (crypto, stocks, ETFs, precious metals). Ideal for European investors who want to spend their gains without going through an external exchange. Austrian FMA regulation and MiCA compliance position it as one of the safest options in the space for EU residents.`,
  },

  'kraken': {
    fr: `Kraken est le choix des traders avancés et des utilisateurs qui ne font pas de compromis sur la sécurité. Sa carte Visa permet de dépenser directement depuis son compte Kraken avec jusqu'à 2% de cashback en crypto, sans staking requis. L'historique de sécurité irréprochable de Kraken depuis 2011 — aucun hack majeur — est son principal différenciateur sur un marché où les incidents de sécurité sont fréquents.`,
    de: `Kraken ist die Wahl fortgeschrittener Trader und sicherheitsbewusster Nutzer. Die Visa-Karte ermöglicht direkte Ausgaben vom Kraken-Konto mit bis zu 2% Cashback in Krypto, ohne Staking. Krakens makellose Sicherheitsbilanz seit 2011 — kein größerer Hack — ist der wichtigste Unterschied auf einem Markt, wo Sicherheitsvorfälle häufig sind.`,
    es: `Kraken es la elección de traders avanzados y usuarios que no comprometen la seguridad. Su tarjeta Visa permite gastar directamente desde la cuenta Kraken con hasta 2% de cashback en cripto sin staking. El historial de seguridad impecable de Kraken desde 2011 — ningún hack importante — es su principal diferenciador en un mercado donde los incidentes son frecuentes.`,
    it: `Kraken è la scelta dei trader avanzati e degli utenti che non scendono a compromessi sulla sicurezza. La carta Visa consente di spendere direttamente dal conto Kraken con fino al 2% di cashback in cripto senza staking. La storia di sicurezza impeccabile di Kraken dal 2011 — nessun hack importante — è il suo principale differenziatore in un mercato dove gli incidenti sono frequenti.`,
    en: `Kraken is the choice for advanced traders and security-conscious users who make no compromises. Its Visa card lets you spend directly from your Kraken account with up to 2% crypto cashback, no staking required. Kraken's flawless security record since 2011 — no major hack — is its defining differentiator in a market where security incidents are common.`,
  },

  'deblock': {
    fr: `Deblock est la solution naturelle pour les résidents français qui veulent une vraie banque crypto — pas un exchange qui propose une carte, mais un établissement financier agréé avec IBAN FR. Le self-custody intégré la différencie radicalement de Revolut ou Coinbase : vous gardez réellement la propriété de vos actifs. Idéale pour les utilisateurs soucieux de leur souveraineté financière et de la conformité réglementaire française.`,
    de: `Deblock ist die natürliche Lösung für französische Einwohner, die eine echte Krypto-Bank wollen — keine Exchange mit Karte, sondern ein zugelassenes Finanzinstitut mit FR-IBAN. Das integrierte Self-Custody unterscheidet sie radikal von Revolut oder Coinbase: Sie behalten wirklich das Eigentum an Ihren Vermögenswerten. Ideal für Nutzer, die Wert auf finanzielle Souveränität und französische regulatorische Konformität legen.`,
    es: `Deblock es la solución natural para los residentes franceses que quieren un verdadero banco cripto — no un exchange que ofrece una tarjeta, sino una entidad financiera autorizada con IBAN FR. El self-custody integrado la diferencia radicalmente de Revolut o Coinbase: realmente mantienes la propiedad de tus activos. Ideal para usuarios que valoran la soberanía financiera y el cumplimiento regulatorio francés.`,
    it: `Deblock è la soluzione naturale per i residenti francesi che vogliono una vera banca cripto — non un exchange che offre una carta, ma un istituto finanziario autorizzato con IBAN FR. Il self-custody integrato la differenzia radicalmente da Revolut o Coinbase: si mantiene davvero la proprietà dei propri asset. Ideale per gli utenti attenti alla sovranità finanziaria e alla conformità regolamentare francese.`,
    en: `Deblock is the natural solution for French residents who want a genuine crypto bank — not an exchange that offers a card, but a licensed financial institution with a French IBAN. Integrated self-custody radically sets it apart from Revolut or Coinbase: you actually retain ownership of your assets. Ideal for users who care about financial sovereignty and French regulatory compliance.`,
  },

  'revolut': {
    fr: `Revolut est la passerelle la plus accessible entre la banque traditionnelle et la crypto pour le grand public. Avec des dizaines de millions de clients en Europe, elle offre une expérience unifiée : compte courant, investissements en crypto et en actions, change de devises — le tout depuis une seule app. La carte Metal reste son tier le plus complet, avec du cashback en crypto et des assurances voyage incluses.`,
    de: `Revolut ist das zugänglichste Tor zwischen traditionellem Banking und Krypto für den Massenmarkt. Mit Dutzenden Millionen Kunden in Europa bietet es eine einheitliche Erfahrung: Girokonto, Krypto- und Aktieninvestitionen, Währungswechsel — alles aus einer App. Die Metal-Karte bleibt der umfassendste Tier mit Krypto-Cashback und inkludierten Reiseversicherungen.`,
    es: `Revolut es la puerta de entrada más accesible entre la banca tradicional y la cripto para el gran público. Con decenas de millones de clientes en Europa, ofrece una experiencia unificada: cuenta corriente, inversiones en cripto y acciones, cambio de divisas — todo desde una sola app. La tarjeta Metal sigue siendo el nivel más completo, con cashback en cripto y seguros de viaje incluidos.`,
    it: `Revolut è la porta d'accesso più accessibile tra la banca tradizionale e la cripto per il grande pubblico. Con decine di milioni di clienti in Europa, offre un'esperienza unificata: conto corrente, investimenti in cripto e azioni, cambio valuta — tutto da un'unica app. La carta Metal rimane il livello più completo, con cashback in cripto e assicurazioni viaggio incluse.`,
    en: `Revolut is the most accessible gateway between traditional banking and crypto for the mainstream user. With tens of millions of customers across Europe, it delivers a unified experience: current account, crypto and stock investments, currency exchange — all from one app. The Metal card remains its most complete tier, with crypto cashback and travel insurance included.`,
  },

  'ledger': {
    fr: `La carte Ledger est unique sur le marché : conçue par le leader mondial des hardware wallets, elle s'adresse aux utilisateurs qui considèrent la sécurité comme non négociable. Elle s'intègre nativement à l'écosystème Ledger (Ledger Live, Nano, Stax), permettant de gérer carte et cold storage depuis la même interface. C'est le choix cohérent pour un utilisateur Ledger existant qui veut étendre sa philosophie de sécurité à ses dépenses quotidiennes.`,
    de: `Die Ledger-Karte ist auf dem Markt einzigartig: Sie wurde vom Weltmarktführer für Hardware-Wallets für Nutzer entwickelt, die Sicherheit als nicht verhandelbar betrachten. Sie integriert sich nativ in das Ledger-Ökosystem (Ledger Live, Nano, Stax) und ermöglicht die Verwaltung von Karte und Cold Storage über dieselbe Oberfläche. Die kohärente Wahl für bestehende Ledger-Nutzer, die ihre Sicherheitsphilosophie auf Alltagsausgaben ausdehnen möchten.`,
    es: `La tarjeta Ledger es única en el mercado: diseñada por el líder mundial en hardware wallets, se dirige a usuarios que consideran la seguridad innegociable. Se integra nativamente en el ecosistema Ledger (Ledger Live, Nano, Stax), permitiendo gestionar la tarjeta y el cold storage desde la misma interfaz. La elección coherente para un usuario existente de Ledger que quiere extender su filosofía de seguridad a sus gastos cotidianos.`,
    it: `La carta Ledger è unica sul mercato: progettata dal leader mondiale degli hardware wallet, si rivolge agli utenti che considerano la sicurezza non negoziabile. Si integra nativamente nell'ecosistema Ledger (Ledger Live, Nano, Stax), permettendo di gestire carta e cold storage dalla stessa interfaccia. La scelta coerente per un utente Ledger esistente che vuole estendere la propria filosofia di sicurezza alle spese quotidiane.`,
    en: `The Ledger card is unique on the market: built by the world leader in hardware wallets, it targets users who consider security non-negotiable. It integrates natively with the Ledger ecosystem (Ledger Live, Nano, Stax), letting you manage your card and cold storage from the same interface. The coherent choice for an existing Ledger user who wants to extend their security philosophy to everyday spending.`,
  },

  'trade-republic': {
    fr: `Trade Republic est le seul émetteur de carte à proposer un système de "Saveback" : une partie de chaque achat est automatiquement réinvestie en ETF ou en crypto. Elle cible les épargnants disciplinés qui veulent faire travailler chaque euro dépensé pour leur avenir financier, sans effort supplémentaire. La carte est gratuite (5€ one-time pour la physique), avec un compte épargne intégré à 4%+ d'intérêts annuels.`,
    de: `Trade Republic ist der einzige Kartenanbieter mit einem "Saveback"-System: Ein Teil jedes Einkaufs wird automatisch in ETFs oder Krypto reinvestiert. Zielgruppe sind disziplinierte Sparer, die jeden ausgegebenen Euro für ihre finanzielle Zukunft arbeiten lassen möchten, ohne zusätzlichen Aufwand. Die Karte ist kostenlos (5€ einmalig für die physische), mit integriertem Sparkonto ab 4%+ Jahreszinsen.`,
    es: `Trade Republic es el único emisor de tarjeta con un sistema "Saveback": parte de cada compra se reinvierte automáticamente en ETFs o cripto. Va dirigida a ahorradores disciplinados que quieren hacer trabajar cada euro gastado para su futuro financiero, sin esfuerzo adicional. La tarjeta es gratuita (5€ única vez para la física), con cuenta de ahorro integrada al 4%+ de intereses anuales.`,
    it: `Trade Republic è l'unico emittente di carte con un sistema "Saveback": una parte di ogni acquisto viene automaticamente reinvestita in ETF o cripto. Si rivolge ai risparmiatori disciplinati che vogliono far lavorare ogni euro speso per il proprio futuro finanziario, senza sforzo aggiuntivo. La carta è gratuita (5€ una tantum per la fisica), con conto risparmio integrato al 4%+ di interessi annuali.`,
    en: `Trade Republic is the only card issuer with a "Saveback" system: a portion of every purchase is automatically reinvested in ETFs or crypto. It targets disciplined savers who want every euro spent working towards their financial future, with no extra effort. The card is free (€5 one-time for the physical), with an integrated savings account earning 4%+ annual interest.`,
  },

  'bleap': {
    fr: `Bleap est la carte Web3 native, conçue pour les utilisateurs qui vivent dans l'écosystème DeFi et veulent une continuité entre leur vie on-chain et leurs dépenses du monde réel. Elle permet de dépenser directement depuis des wallets compatibles (Ethereum, Layer 2) sans passer par un exchange centralisé. C'est le choix des power users DeFi qui veulent utiliser leurs yields et leur liquidité on-chain sans friction.`,
    de: `Bleap ist die native Web3-Karte für Nutzer, die im DeFi-Ökosystem leben und Kontinuität zwischen On-Chain-Leben und realen Ausgaben wollen. Sie ermöglicht direkte Ausgaben aus kompatiblen Wallets (Ethereum, Layer 2) ohne zentralisierte Exchange. Die Wahl der DeFi-Power-User, die ihre Yields und On-Chain-Liquidität reibungslos nutzen möchten.`,
    es: `Bleap es la tarjeta Web3 nativa, diseñada para usuarios que viven en el ecosistema DeFi y quieren continuidad entre su vida on-chain y sus gastos en el mundo real. Permite gastar directamente desde wallets compatibles (Ethereum, Layer 2) sin pasar por un exchange centralizado. La elección de los power users DeFi que quieren usar sus yields y liquidez on-chain sin fricción.`,
    it: `Bleap è la carta Web3 nativa, progettata per gli utenti che vivono nell'ecosistema DeFi e vogliono continuità tra la loro vita on-chain e le spese nel mondo reale. Permette di spendere direttamente da wallet compatibili (Ethereum, Layer 2) senza passare per un exchange centralizzato. La scelta dei power user DeFi che vogliono usare i loro yield e la liquidità on-chain senza attrito.`,
    en: `Bleap is the native Web3 card, built for users who live in the DeFi ecosystem and want continuity between their on-chain life and real-world spending. It enables direct spending from compatible wallets (Ethereum, Layer 2) without going through a centralised exchange. The choice for DeFi power users who want to deploy their yields and on-chain liquidity without friction.`,
  },

  'plutus': {
    fr: `Plutus est pensée pour les passionnés de DeFi et les crypto-natifs qui veulent récompenser chaque achat avec du PLUT, le token natif de la plateforme. Les "perks" mensuels permettent d'être remboursé pour des abonnements populaires (Netflix, Spotify, Amazon) selon le niveau de staking, créant un vrai écosystème de récompenses interconnectées. C'est le choix des early adopters qui croient à long terme dans le modèle économique Plutus.`,
    de: `Plutus ist für DeFi-Enthusiasten und Crypto-Natives konzipiert, die jeden Einkauf mit PLUT, dem nativen Token der Plattform, belohnen möchten. Monatliche "Perks" ermöglichen Rückerstattungen für beliebte Abonnements (Netflix, Spotify, Amazon) je nach Staking-Level, was ein echtes Netzwerk verknüpfter Belohnungen schafft. Die Wahl der Early Adopter, die langfristig an das Plutus-Wirtschaftsmodell glauben.`,
    es: `Plutus está pensada para los entusiastas de DeFi y los cripto-nativos que quieren recompensar cada compra con PLUT, el token nativo de la plataforma. Los "perks" mensuales permiten ser reembolsado por suscripciones populares (Netflix, Spotify, Amazon) según el nivel de staking, creando un verdadero ecosistema de recompensas interconectadas. La elección de los early adopters que creen a largo plazo en el modelo económico de Plutus.`,
    it: `Plutus è pensata per gli appassionati di DeFi e i crypto-nativi che vogliono premiare ogni acquisto con PLUT, il token nativo della piattaforma. I "perk" mensili permettono di essere rimborsati per abbonamenti popolari (Netflix, Spotify, Amazon) in base al livello di staking, creando un vero ecosistema di ricompense interconnesse. La scelta degli early adopter che credono nel lungo termine nel modello economico di Plutus.`,
    en: `Plutus is designed for DeFi enthusiasts and crypto-natives who want to reward every purchase with PLUT, the platform's native token. Monthly perks reimburse popular subscriptions (Netflix, Spotify, Amazon) based on staking level, creating a genuine interconnected rewards ecosystem. The choice for early adopters who believe in the long-term Plutus economic model.`,
  },

  'gnosis': {
    fr: `La carte Gnosis Pay est pionnière dans son approche : première carte de débit entièrement ancrée sur la blockchain Gnosis Chain, elle permet de dépenser du xDAI directement depuis un wallet Gnosis Safe, sans intermédiaire custodial. C'est une solution pour les maximalistes de la décentralisation qui refusent tout compromis sur la transparence et la non-custodialité. Idéale pour les développeurs et utilisateurs avancés de l'écosystème Gnosis.`,
    de: `Die Gnosis Pay-Karte ist in ihrem Ansatz wegweisend: erste Debitkarte, die vollständig auf der Gnosis Chain Blockchain verankert ist, ermöglicht xDAI-Ausgaben direkt aus einer Gnosis Safe-Wallet ohne Custody-Intermediär. Eine Lösung für Dezentralisierungs-Maximalisten, die keine Kompromisse bei Transparenz und Non-Custodialität eingehen. Ideal für Entwickler und Power-User des Gnosis-Ökosystems.`,
    es: `La tarjeta Gnosis Pay es pionera en su enfoque: primera tarjeta de débito completamente anclada en la blockchain Gnosis Chain, permite gastar xDAI directamente desde una wallet Gnosis Safe sin intermediario custodial. Una solución para los maximalistas de la descentralización que no aceptan compromisos en transparencia y no-custodia. Ideal para desarrolladores y usuarios avanzados del ecosistema Gnosis.`,
    it: `La carta Gnosis Pay è pionieristica nel suo approccio: prima carta di debito completamente ancorata alla blockchain Gnosis Chain, permette di spendere xDAI direttamente da un wallet Gnosis Safe senza intermediario custodiale. Una soluzione per i massimalisti della decentralizzazione che non accettano compromessi su trasparenza e non-custodia. Ideale per sviluppatori e utenti avanzati dell'ecosistema Gnosis.`,
    en: `The Gnosis Pay card is pioneering in its approach: the first debit card fully anchored on the Gnosis Chain blockchain, enabling xDAI spending directly from a Gnosis Safe wallet with no custodial intermediary. A solution for decentralisation maximalists who accept no compromise on transparency and non-custody. Ideal for developers and power users of the Gnosis ecosystem.`,
  },

  'brighty': {
    fr: `Brighty est taillée pour les utilisateurs qui souhaitent explorer le monde crypto sans prise de risque excessive. Gratuite, avec un IBAN européen, un cashback en USDC (stablecoin) et sans aucun staking requis, elle est idéale pour les débutants et les profils prudents. Son modèle 100 % USDC élimine la volatilité des tokens propriétaires, offrant un cashback à valeur stable et prévisible — un argument de poids pour ceux qui n'ont pas encore d'exposition crypto mais veulent s'y initier en douceur.`,
    de: `Brighty ist die ideale Wahl für Nutzer, die die Krypto-Welt ohne übermäßiges Risiko erkunden möchten. Kostenlos, mit europäischer IBAN, USDC-Cashback (Stablecoin) und ohne Staking-Pflicht — perfekt für Einsteiger und vorsichtige Nutzer. Das reine USDC-Modell eliminiert die Volatilität proprietärer Token und bietet stabilen, vorhersehbaren Cashback. Ein starkes Argument für alle, die noch keine Krypto-Exposition haben, sich aber sanft einführen möchten.`,
    es: `Brighty es la opción ideal para usuarios que quieren explorar el mundo cripto sin riesgo excesivo. Gratuita, con IBAN europeo, cashback en USDC (stablecoin) y sin staking requerido — perfecta para principiantes y usuarios prudentes. Su modelo 100% USDC elimina la volatilidad de los tokens propietarios y ofrece un cashback estable y predecible. Un argumento clave para quienes aún no tienen exposición cripto pero quieren iniciarse con suavidad.`,
    it: `Brighty è la scelta ideale per gli utenti che vogliono esplorare il mondo crypto senza rischi eccessivi. Gratuita, con IBAN europeo, cashback in USDC (stablecoin) e senza staking richiesto — perfetta per principianti e utenti prudenti. Il modello 100% USDC elimina la volatilità dei token proprietari e offre un cashback stabile e prevedibile. Un argomento chiave per chi non ha ancora esposizione crypto ma vuole avvicinarsi con gradualità.`,
    en: `Brighty is the ideal choice for users who want to explore the crypto world without excessive risk. Free, with a European IBAN, USDC cashback (stablecoin), and no staking required — perfect for beginners and cautious users. The 100% USDC model eliminates the volatility of proprietary tokens, offering stable and predictable cashback. A compelling case for those with no crypto exposure yet who want a gentle introduction.`,
  },

  'metamask': {
    fr: `MetaMask Card est conçue pour les utilisateurs Web3 qui veulent une passerelle entre leur wallet décentralisé et le monde physique. Compatible avec l'écosystème MetaMask existant, elle permet de dépenser directement depuis un portefeuille self-custody sans intermédiaire centralisé. Idéale pour les utilisateurs DeFi qui refusent de confier leurs fonds à une plateforme centralisée, tout en bénéficiant d'un cashback en USDC sur chaque achat — une combinaison rare entre souveraineté financière et utilité quotidienne.`,
    de: `MetaMask Card ist für Web3-Nutzer konzipiert, die eine Brücke zwischen ihrer dezentralisierten Wallet und der physischen Welt suchen. Kompatibel mit dem bestehenden MetaMask-Ökosystem, ermöglicht sie direkte Ausgaben aus einer Self-Custody-Wallet ohne zentralen Intermediär. Ideal für DeFi-Nutzer, die ihre Gelder keiner zentralisierten Plattform anvertrauen möchten — mit USDC-Cashback auf jeden Einkauf. Eine seltene Kombination aus finanzieller Souveränität und Alltagstauglichkeit.`,
    es: `MetaMask Card está diseñada para usuarios Web3 que buscan un puente entre su wallet descentralizada y el mundo físico. Compatible con el ecosistema MetaMask existente, permite gastar directamente desde una cartera de autocustodia sin intermediario centralizado. Ideal para usuarios DeFi que no quieren confiar sus fondos a una plataforma centralizada, obteniendo cashback en USDC en cada compra — una combinación única de soberanía financiera y utilidad cotidiana.`,
    it: `MetaMask Card è pensata per gli utenti Web3 che vogliono un ponte tra il loro wallet decentralizzato e il mondo fisico. Compatibile con l'ecosistema MetaMask esistente, permette di spendere direttamente dal proprio portafoglio self-custody senza intermediari centralizzati. Ideale per gli utenti DeFi che non vogliono affidare i propri fondi a una piattaforma centralizzata — con cashback in USDC su ogni acquisto. Una combinazione unica di sovranità finanziaria e utilità quotidiana.`,
    en: `MetaMask Card is built for Web3 users who want a bridge between their decentralised wallet and the physical world. Compatible with the existing MetaMask ecosystem, it enables spending directly from your self-custody wallet with no centralised intermediary. Ideal for DeFi users who don't want to entrust funds to a centralised platform — with USDC cashback on every purchase. A rare combination of financial sovereignty and everyday usability.`,
  },

  'ether-fi': {
    fr: `Ether.fi Cash est le choix de référence pour les holders ETH qui ne veulent pas arbitrer entre utilité quotidienne et exposition DeFi. En self-custody natif, votre cashback en weETH continue à générer du rendement EigenLayer après chaque dépense — une mécanique unique qu'aucune carte centralisée ne peut reproduire. Zéro frais, aucun staking de token propriétaire requis : si vous êtes déjà dans l'écosystème Ether.fi, cette carte est l'extension naturelle de votre stratégie.`,
    de: `Ether.fi Cash ist die erste Wahl für ETH-Holder, die nicht zwischen Alltagsnutzen und DeFi-Exposure wählen wollen. Mit nativem Self-Custody generiert Ihr weETH-Cashback nach jeder Ausgabe weiterhin EigenLayer-Rendite — eine einzigartige Mechanik, die kein zentralisierter Anbieter replizieren kann. Null Gebühren, kein Staking proprietärer Token erforderlich: Wer bereits im Ether.fi-Ökosystem aktiv ist, findet hier die natürliche Erweiterung seiner Strategie.`,
    es: `Ether.fi Cash es la referencia para los holders de ETH que no quieren elegir entre utilidad cotidiana y exposición DeFi. Con self-custody nativo, tu cashback en weETH sigue generando rendimiento EigenLayer después de cada gasto — una mecánica única que ningún proveedor centralizado puede replicar. Cero comisiones, sin staking de token propietario requerido: si ya estás en el ecosistema Ether.fi, esta tarjeta es la extensión natural de tu estrategia.`,
    it: `Ether.fi Cash è il riferimento per i holder ETH che non vogliono scegliere tra utilità quotidiana ed esposizione DeFi. Con self-custody nativo, il tuo cashback in weETH continua a generare rendimento EigenLayer dopo ogni spesa — una meccanica unica che nessun fornitore centralizzato può replicare. Zero commissioni, nessuno staking di token proprietario richiesto: se sei già nell'ecosistema Ether.fi, questa carta è l'estensione naturale della tua strategia.`,
    en: `Ether.fi Cash is the go-to for ETH holders who don't want to choose between everyday usability and DeFi exposure. With native self-custody, your weETH cashback keeps generating EigenLayer yield after every spend — a unique mechanic no centralised card can replicate. Zero fees, no proprietary token staking required: if you're already in the Ether.fi ecosystem, this card is the natural extension of your strategy.`,
  },

  'bitget': {
    fr: `La carte Bitget est la solution naturelle pour les traders actifs sur l'exchange Bitget, 5e mondial. Sans frais annuels et avec une intégration directe de votre compte, elle transforme votre solde trading en pouvoir d'achat quotidien dans 180+ pays. Son fonds de protection de 300 M$ apporte un niveau de confiance supplémentaire dans un secteur offshore. Idéale pour les utilisateurs Bitget qui veulent simplifier leur gestion crypto-fiat sans changer de plateforme.`,
    de: `Die Bitget-Karte ist die natürliche Lösung für aktive Trader auf der Bitget-Exchange, der fünftgrößten weltweit. Ohne Jahresgebühren und mit direkter Kontoverknüpfung verwandeln Sie Ihr Trading-Guthaben in tägliche Kaufkraft in 180+ Ländern. Der 300-Mio.-$-Schutzfonds schafft zusätzliches Vertrauen in einem Offshore-Umfeld. Ideal für Bitget-Nutzer, die ihr Krypto-Fiat-Management vereinfachen wollen, ohne die Plattform zu wechseln.`,
    es: `La tarjeta Bitget es la solución natural para los traders activos en el exchange Bitget, el 5º del mundo. Sin comisiones anuales y con integración directa de tu cuenta, transforma tu saldo de trading en poder adquisitivo diario en 180+ países. Su fondo de protección de 300 M$ aporta un nivel adicional de confianza en un entorno offshore. Ideal para usuarios de Bitget que quieren simplificar su gestión cripto-fiat sin cambiar de plataforma.`,
    it: `La carta Bitget è la soluzione naturale per i trader attivi sull'exchange Bitget, il 5° al mondo. Senza commissioni annuali e con integrazione diretta del tuo conto, trasforma il tuo saldo di trading in potere d'acquisto quotidiano in 180+ paesi. Il suo fondo di protezione da 300 M$ offre un livello aggiuntivo di fiducia in un contesto offshore. Ideale per gli utenti Bitget che vogliono semplificare la gestione cripto-fiat senza cambiare piattaforma.`,
    en: `The Bitget Card is the natural solution for active traders on the Bitget exchange, the fifth-largest in the world. With no annual fees and direct account integration, it turns your trading balance into everyday purchasing power in 180+ countries. The 300M$ protection fund adds an extra layer of confidence in an offshore environment. Ideal for Bitget users who want to simplify their crypto-fiat management without switching platforms.`,
  },

  'kucoin': {
    fr: `La KuCard est l'extension logique du compte KuCoin pour les utilisateurs qui veulent monétiser leurs cryptos au quotidien. Avec un cashback de 1 à 3% en KCS et l'un des plus larges catalogues d'actifs disponibles, elle convient parfaitement aux traders diversifiés. La résilience de KuCoin après le hack 2020 (remboursement intégral) est un signal de sérieux dans la gestion de crise. À noter : l'accord DOJ 2024 sur l'AML appelle à la prudence pour les résidents européens soucieux de conformité réglementaire.`,
    de: `Die KuCard ist die logische Erweiterung des KuCoin-Kontos für Nutzer, die ihre Kryptos im Alltag monetarisieren wollen. Mit 1-3% Cashback in KCS und einem der größten Angebote verfügbarer Assets eignet sie sich perfekt für diversifizierte Trader. Die Resilienz von KuCoin nach dem Hack 2020 (vollständige Rückerstattung) signalisiert ernsthaftes Krisenmanagement. Hinweis: Der DOJ-Vergleich 2024 zum Thema AML mahnt zur Vorsicht für EU-Einwohner mit hohen Compliance-Anforderungen.`,
    es: `La KuCard es la extensión lógica de la cuenta KuCoin para usuarios que quieren monetizar sus criptos en el día a día. Con cashback del 1 al 3% en KCS y uno de los catálogos más amplios de activos disponibles, es perfecta para traders diversificados. La resiliencia de KuCoin tras el hack de 2020 (reembolso íntegro) es una señal de seriedad en la gestión de crisis. A tener en cuenta: el acuerdo DOJ 2024 sobre AML invita a la prudencia para los residentes europeos preocupados por el cumplimiento regulatorio.`,
    it: `La KuCard è l'estensione logica del conto KuCoin per gli utenti che vogliono monetizzare le proprie cripto nella vita quotidiana. Con cashback dall'1 al 3% in KCS e uno dei più ampi cataloghi di asset disponibili, è perfetta per i trader diversificati. La resilienza di KuCoin dopo l'hack del 2020 (rimborso integrale) è un segnale di serietà nella gestione delle crisi. Da notare: l'accordo DOJ 2024 sull'AML invita alla cautela per i residenti europei attenti alla conformità normativa.`,
    en: `The KuCard is the logical extension of a KuCoin account for users who want to monetise their crypto daily. With 1-3% cashback in KCS and one of the widest catalogues of available assets, it suits diversified traders perfectly. KuCoin's resilience after the 2020 hack (full reimbursement) signals serious crisis management. Note: the 2024 DOJ settlement on AML warrants caution for EU residents with high compliance expectations.`,
  },

  'young-platform': {
    fr: `Young Platform est LE choix pour les résidents italiens qui veulent une carte crypto réglementée, en italien, avec un vrai ancrage local. Première plateforme crypto italienne certifiée MiCA, elle offre un niveau de conformité réglementaire exceptionnel pour le marché IT. Avec plus d'1 million d'utilisateurs et un cashback allant jusqu'à 3,6% en YNG, elle combine masse critique, confiance institutionnelle et avantages fidélité. La référence absolue pour le marché crypto italien.`,
    de: `Young Platform ist DIE Wahl für italienische Einwohner, die eine regulierte Kryptokarte auf Italienisch mit echtem lokalem Verankerung wünschen. Als erste MiCA-zertifizierte Kryptoplattform Italiens bietet sie außergewöhnliche Regulierungskonformität für den IT-Markt. Mit über 1 Million Nutzern und bis zu 3,6% Cashback in YNG kombiniert sie kritische Masse, institutionelles Vertrauen und Treuevorteile. Die absolute Referenz für den italienischen Kryptomarkt.`,
    es: `Young Platform es LA elección para los residentes italianos que quieren una tarjeta cripto regulada, en italiano, con un arraigo local real. Primera plataforma cripto italiana certificada MiCA, ofrece un nivel de conformidad regulatoria excepcional para el mercado IT. Con más de 1 millón de usuarios y un cashback de hasta el 3,6% en YNG, combina masa crítica, confianza institucional y ventajas de fidelidad. La referencia absoluta para el mercado cripto italiano.`,
    it: `Young Platform è LA scelta per i residenti italiani che vogliono una carta cripto regolamentata, in italiano, con un vero radicamento locale. Prima piattaforma cripto italiana certificata MiCA, offre un livello di conformità normativa eccezionale per il mercato IT. Con oltre 1 milione di utenti e cashback fino al 3,6% in YNG, combina massa critica, fiducia istituzionale e vantaggi fedeltà. Il riferimento assoluto per il mercato cripto italiano.`,
    en: `Young Platform is THE choice for Italian residents who want a regulated crypto card, in Italian, with genuine local roots. As Italy's first MiCA-certified crypto platform, it offers exceptional regulatory compliance for the Italian market. With over 1 million users and cashback of up to 3.6% in YNG, it combines critical mass, institutional trust and loyalty rewards. The absolute reference for the Italian crypto market.`,
  },

  'bit2me': {
    fr: `Bit2Me est l'exchange crypto le plus ancien et le plus réglementé d'Espagne — un gage de solidité rare dans l'espace crypto UE. Avec la régulation CNMV + Banco de España et une carte Mastercard offrant jusqu'à 7% de cashback en B2M, c'est l'option évidente pour les résidents espagnols qui veulent une carte crypto de confiance avec un ancrage réglementaire local fort. 12 ans d'existence en font l'une des références de longévité du secteur.`,
    de: `Bit2Me ist Spaniens älteste und am stärksten regulierte Kryptobörse — ein seltenes Zeichen von Solidität im EU-Krypto-Raum. Mit CNMV- und Banco de España-Regulierung sowie einer Mastercard mit bis zu 7% Cashback in B2M ist sie die naheliegende Option für spanische Einwohner, die eine vertrauenswürdige Kryptokarte mit starker lokaler Regulierung wollen. 12 Jahre Bestehen machen sie zu einer der langlebigsten Referenzen des Sektors.`,
    es: `Bit2Me es el exchange cripto más antiguo y más regulado de España — una garantía de solidez poco común en el espacio cripto de la UE. Con la regulación de la CNMV + Banco de España y una tarjeta Mastercard con hasta el 7% de cashback en B2M, es la opción obvia para los residentes españoles que quieren una tarjeta cripto de confianza con un fuerte arraigo regulatorio local. 12 años de existencia la convierten en una de las referencias de longevidad del sector.`,
    it: `Bit2Me è il più antico e regolamentato exchange cripto della Spagna — una garanzia di solidità rara nel panorama cripto UE. Con la regolamentazione CNMV + Banco de España e una carta Mastercard con cashback fino al 7% in B2M, è l'opzione ovvia per i residenti spagnoli che vogliono una carta cripto affidabile con un forte ancoraggio regolatorio locale. 12 anni di esistenza ne fanno uno dei riferimenti di longevità del settore.`,
    en: `Bit2Me is Spain's oldest and most regulated crypto exchange — a rare mark of solidity in the EU crypto space. With CNMV + Banco de España regulation and a Mastercard offering up to 7% cashback in B2M, it's the obvious choice for Spanish residents who want a trusted crypto card with strong local regulatory roots. 12 years in operation make it one of the sector's longevity references.`,
  },

  'whitebit': {
    fr: `WhiteBIT Nóva se distingue par le cashback le plus élevé du marché (jusqu'à 10% en WBT) et un score de sécurité CER.live maximum — une rareté dans l'espace crypto. Émise via Wallester AS (régulé UE, Estonie), la carte offre un cadre légal solide malgré la localisation de l'exchange. Pour les utilisateurs actifs de WhiteBIT prêts à staker du WBT, c'est une proposition difficile à égaler en termes de rendement sur les dépenses quotidiennes.`,
    de: `WhiteBIT Nóva hebt sich durch das höchste Cashback auf dem Markt hervor (bis zu 10% in WBT) und einen maximalen CER.live-Sicherheitsscore — eine Seltenheit im Krypto-Bereich. Über Wallester AS (EU-reguliert, Estland) ausgegeben, bietet die Karte einen soliden Rechtsrahmen trotz der Exchange-Lokalisierung. Für aktive WhiteBIT-Nutzer, die bereit sind, WBT zu staken, ist dies ein schwer zu übertreffendes Angebot in Bezug auf tägliche Ausgabenrendite.`,
    es: `WhiteBIT Nóva se distingue por el cashback más alto del mercado (hasta el 10% en WBT) y una puntuación de seguridad máxima de CER.live — una rareza en el espacio cripto. Emitida vía Wallester AS (regulado en UE, Estonia), la tarjeta ofrece un marco legal sólido a pesar de la localización del exchange. Para los usuarios activos de WhiteBIT dispuestos a hacer staking de WBT, es una propuesta difícil de igualar en términos de rendimiento sobre los gastos diarios.`,
    it: `WhiteBIT Nóva si distingue per il cashback più alto del mercato (fino al 10% in WBT) e un punteggio di sicurezza massimo CER.live — una rarità nel panorama cripto. Emessa tramite Wallester AS (regolamentato UE, Estonia), la carta offre un solido quadro legale nonostante la localizzazione dell'exchange. Per gli utenti attivi di WhiteBIT disposti a fare staking di WBT, è una proposta difficile da eguagliare in termini di rendimento sulle spese quotidiane.`,
    en: `WhiteBIT Nóva stands out for the highest cashback on the market (up to 10% in WBT) and a maximum CER.live security score — a rarity in the crypto space. Issued via Wallester AS (EU-regulated, Estonia), the card offers a solid legal framework despite the exchange's offshore location. For active WhiteBIT users willing to stake WBT, it's a hard-to-beat proposition in terms of daily spending yield.`,
  },

  'gate': {
    fr: `Gate.io est l'un des exchanges les plus anciens et les plus complets du marché (depuis 2013), avec plus de 1 600 cryptos listées. Sa Gate Card offre un cashback en GT (Gate Token) sans frais annuels — une extension naturelle pour les utilisateurs déjà actifs sur la plateforme. La longévité de l'exchange et sa profondeur de liquidité sont des atouts reconnus. Prudence cependant : Gate.io n'est pas régulé en UE, un point important pour les résidents européens.`,
    de: `Gate.io ist eine der ältesten und umfangreichsten Kryptobörsen auf dem Markt (seit 2013), mit über 1.600 gelisteten Kryptos. Die Gate Card bietet GT-Cashback ohne Jahresgebühren — eine natürliche Erweiterung für bereits auf der Plattform aktive Nutzer. Das hohe Alter der Exchange und ihre Liquiditätstiefe sind anerkannte Stärken. Vorsicht jedoch: Gate.io ist nicht in der EU reguliert, ein wichtiger Punkt für europäische Einwohner.`,
    es: `Gate.io es uno de los exchanges más antiguos y completos del mercado (desde 2013), con más de 1.600 criptos listadas. Su Gate Card ofrece cashback en GT (Gate Token) sin comisiones anuales — una extensión natural para los usuarios ya activos en la plataforma. La longevidad del exchange y su profundidad de liquidez son fortalezas reconocidas. Sin embargo, prudencia: Gate.io no está regulado en la UE, un punto importante para los residentes europeos.`,
    it: `Gate.io è uno degli exchange più antichi e completi del mercato (dal 2013), con oltre 1.600 crypto quotate. La sua Gate Card offre cashback in GT (Gate Token) senza commissioni annuali — un'estensione naturale per gli utenti già attivi sulla piattaforma. La longevità dell'exchange e la sua profondità di liquidità sono punti di forza riconosciuti. Attenzione però: Gate.io non è regolamentato nell'UE, un punto importante per i residenti europei.`,
    en: `Gate.io is one of the oldest and most comprehensive exchanges on the market (since 2013), with over 1,600 listed cryptos. Its Gate Card offers GT cashback with no annual fees — a natural extension for users already active on the platform. The exchange's longevity and liquidity depth are recognised strengths. A note of caution: Gate.io is not EU-regulated, an important consideration for European residents.`,
  },
};
